SELECT C.FUNCAO FROM CARGO C JOIN SERVIDOR S ON S.PK_SIAPE = C.FK_SIAPE WHERE C.SIGLA_CAMPUS = 'GYN' AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%ciencia da computacao%') AND C.DATA_ENTRADA <= DATE('now') AND COALESCE(C.DATA_SAIDA, DATE('now')) >= DATE('now', '-5 years') GROUP BY C.FUNCAO ORDER BY COUNT(*) DESC LIMIT 1